import sys

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out = []
    for _ in range(T):
        X = int(next(it)); Y = int(next(it)); Z = int(next(it))
        if X + Y <= Z:
            out.append('2')
        elif X <= Z:
            out.append('1')
        else:
            out.append('0')
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    solve()

